// Get metadata for reference
const meta = $input.first().json.search_metadata;

// Get flight data
const data = $input.first().json;

// Combine flights from both best_flights and other_flights
const flights = []
  .concat(data.best_flights || [])
  .concat(data.other_flights || []);

if (!flights.length) {
  return { 
    ok: false, 
    message: "❌ No flight data available", 
    meta
  };
}

// Helper: Convert value to number
function toNumber(v) {
  if (v == null) return null;
  if (typeof v === "number") return v;
  const s = String(v).replace(/[^\d]/g, "");
  return s ? Number(s) : null;
}

// Normalize flight data
const normalized = flights.map(f => {
  const price =
    toNumber(f.price) ??
    toNumber(f?.price?.total) ??
    toNumber(f?.price_str);

  const airline = f.flights?.[0]?.airline || "Unknown airline";
  const dep = f.flights?.[0]?.departure_airport?.time || "";
  const arr = f.flights?.[0]?.arrival_airport?.time || "";

  return { price, airline, dep, arr };
}).filter(x => x.price != null);

if (!normalized.length) {
  return { 
    ok: false, 
    message: "❌ Flights found but no readable price", 
    sample: flights[0] 
  };
}

// Sort by ascending price
normalized.sort((a, b) => a.price - b.price);
const best = normalized[0];

return {
  ok: true,
  minPrice: best.price,
  message:
    `✈️ Cheapest Ticket\n` +
    `Price: ${best.price.toLocaleString("en-US")} USD\n` +
    `Airline: ${best.airline}\n` +
    `Time: ${best.dep} → ${best.arr}`,
  meta
};
